import pytest


def max_subarray_sum(arr: list) -> int:
    if not arr:
        return 0
    max_sum = current = arr[0]
    for num in arr[1:]:
        current = max(num, current + num)
        max_sum = max(max_sum, current)
    return max_sum


# Happy path tests
def test_max_subarray_sum_all_positive():
    assert max_subarray_sum([1, 2, 3]) == 6


def test_max_subarray_sum_mixed_with_max_in_middle():
    # Example: [-2, 1, -3, 4, -1, 2, 1, -5, 4]
    # Max subarray: [4, -1, 2, 1] sum=6
    assert max_subarray_sum([-2, 1, -3, 4, -1, 2, 1, -5, 4]) == 6


def test_max_subarray_sum_single_positive():
    assert max_subarray_sum([5]) == 5


def test_max_subarray_sum_all_positive_with_negatives():
    # Max subarray: entire [1, -1, 2] sum=2
    assert max_subarray_sum([1, -1, 2]) == 2


# Edge cases
def test_max_subarray_sum_empty_list():
    assert max_subarray_sum([]) == 0


def test_max_subarray_sum_single_negative():
    assert max_subarray_sum([-1]) == -1


def test_max_subarray_sum_all_negative():
    # Max is the largest single negative: -1
    assert max_subarray_sum([-2, -3, -1]) == -1


def test_max_subarray_sum_all_negative_with_zero():
    # Zero is not negative, but max should be 0
    assert max_subarray_sum([-2, 0, -1]) == 0


def test_max_subarray_sum_large_numbers():
    # Test with larger values to ensure no overflow (Python ints are arbitrary precision)
    assert max_subarray_sum([1000000, -500000, 600000]) == 1100000


# Error cases (assuming input validation isn't strict, but testing invalid inputs)
def test_max_subarray_sum_non_numeric_list():
    # This will raise TypeError when trying to compare/add non-numbers
    with pytest.raises(TypeError):
        max_subarray_sum([1, "a", 3])


def test_max_subarray_sum_empty_with_none():
    # None in list will cause TypeError
    with pytest.raises(TypeError):
        max_subarray_sum([1, None, 3])


def test_max_subarray_sum_not_list():
    # TypeError if not iterable/list
    with pytest.raises(TypeError):
        max_subarray_sum("not a list")
